mapper.update:
update product
name=#{name}, price=#{price}, stock=#{stock}, category_id=#{categoryId}, status=#{status}, image_url=#{imageUrl},
where id=#{id}

mapper.select:
select p.*, c.name as category_name from product p left join category c on p.category_id=c.id

    and p.name like concat('%',#{keyword},'%')
    and p.category_id=#{categoryId}
    and p.status=#{status}

order by p.id
